++function toArray(v) {
++  if (v == null) return [];
++  return Array.isArray(v) ? v : [v];
++}
++var fromLength = (length) => Array.from(Array(length).keys());
++var first = (v) => v[0];
++var last = (v) => v[v.length - 1];
++var isEmpty = (v) => v.length === 0;
